    private Redis $cache;
    private array $config;
    private int $requestCount = 0;

    public function __construct(
        LoggerInterface $logger,
        Redis $cache,
        array $config = []
    ) {
        $this->logger = $logger;
        $this->cache = $cache;
        $this->config = array_merge([
            'allowed_domains' => [],
            'max_response_size' => 10 * 1024 * 1024, // 10MB
            'timeout' => 10,
            'rate_limit' => 100,
            'rate_window' => 3600,
            'enable_allowlist' => true
        ], $config);
    }

    public function fetchUrl(string $url, string $requesterId): array {
        $requestId = bin2hex(random_bytes(8));
        $startTime = microtime(true);

        try {
            // Layer 1: Rate limiting
            $this->enforceRateLimit($requesterId);

            // Layer 2: URL parsing and validation
            $parsedUrl = $this->parseAndValidateUrl($url);

            // Layer 3: Scheme validation
            $this->validateScheme($parsedUrl['scheme'] ?? '');

            // Layer 4: Host blocklist check
            $host = strtolower($parsedUrl['host']);
            $this->checkHostBlocklist($host);

            // Layer 5: DNS resolution with rebinding protection
            $resolvedIp = $this->resolveDnsSecurely($host, $requestId);

            // Layer 6: IP range validation
            $this->validateIpAddress($resolvedIp);

            // Layer 7: Domain allowlist (if enabled)
            if ($this->config['enable_allowlist']) {
                $this->validateAllowlist($host);
            }

            // Layer 8: Execute request with IP pinning
            $result = $this->executeRequestWithPinnedIp($url, $host, $resolvedIp, $requestId);

            // Layer 9: Response validation
            $this->validateResponse($result, $requestId);

            $this->logSuccess($requestId, $url, $resolvedIp, $requesterId, $startTime);

            return $result;

        } catch (SsrfSecurityException $e) {
            $this->logSecurityEvent($requestId, $url, $requesterId, $e);
            throw $e;
        } catch (\Exception $e) {
            $this->logError($requestId, $url, $requesterId, $e);
            throw new SsrfSecurityException('Request failed', 0, $e);
        }
    }

    private function enforceRateLimit(string $requesterId): void {
        $key = "ssrf_rate:{$requesterId}";
        $current = (int) $this->cache->incr($key);

        if ($current === 1) {
            $this->cache->expire($key, $this->config['rate_window']);
        }

        if ($current > $this->config['rate_limit']) {
            throw new SsrfSecurityException('Rate limit exceeded');
        }
    }

    private function parseAndValidateUrl(string $url): array {
        // Normalize URL to prevent bypass techniques
        $url = trim($url);

        // Block URL encoding tricks
        if (preg_match('/%[0-9a-fA-F]{2}/', $url)) {
            // Double decode to catch %25 encoding
            $decoded = urldecode(urldecode($url));
            if ($decoded !== $url) {
                throw new SsrfSecurityException('URL encoding bypass detected');
            }
        }

