        if (preg_match('/[\x00-\x1f\x7f@#]/', $url)) {
            throw new SsrfSecurityException('Invalid characters in URL');
        }

        $parsedUrl = parse_url($url);
        if ($parsedUrl === false || !isset($parsedUrl['host'])) {
            throw new SsrfSecurityException('Invalid URL format');
        }

        // Check for authentication in URL (potential bypass)
        if (isset($parsedUrl['user']) || isset($parsedUrl['pass'])) {
            throw new SsrfSecurityException('URL authentication not allowed');
        }

        return $parsedUrl;
    }

    private function validateScheme(string $scheme): void {
        if (!in_array(strtolower($scheme), self::ALLOWED_SCHEMES, true)) {
            throw new SsrfSecurityException(
                "Protocol not allowed: {$scheme}. Only HTTP/HTTPS permitted."
            );
        }
    }

    private function checkHostBlocklist(string $host): void {
        // Check exact matches
        if (in_array($host, self::BLOCKED_HOSTS, true)) {
            throw new SsrfSecurityException("Blocked host: {$host}");
        }

        // Check for numeric IP in hostname (bypass attempt)
        if (filter_var($host, FILTER_VALIDATE_IP)) {
            // Validate IP directly
            $this->validateIpAddress($host);
        }

        // Block decimal/octal/hex IP representations
        // Example: 2130706433 = 127.0.0.1
        if (is_numeric($host)) {
            throw new SsrfSecurityException('Numeric IP formats not allowed');
        }

        // Block IPv6 encoded as IPv4
        if (preg_match('/^\[.*\]$/', $host)) {
            throw new SsrfSecurityException('IPv6 format not allowed');
        }
    }

    private function resolveDnsSecurely(string $host, string $requestId): string {
        // Use DNS-over-HTTPS or trusted resolver in production
        $resolvedIp = gethostbyname($host);

        if ($resolvedIp === $host) {
            throw new SsrfSecurityException('DNS resolution failed');
        }

        // Cache the resolution to prevent DNS rebinding
        $cacheKey = "dns_pin:{$host}:" . date('YmdH');
        $cachedIp = $this->cache->get($cacheKey);

        if ($cachedIp !== false && $cachedIp !== $resolvedIp) {
            $this->logger->critical('DNS rebinding attack detected', [
                'request_id' => $requestId,
                'host' => $host,
                'cached_ip' => $cachedIp,
                'new_ip' => $resolvedIp
            ]);
            throw new SsrfSecurityException('DNS rebinding attack detected');
        }

        // Pin the IP for this host
        $this->cache->setex($cacheKey, 3600, $resolvedIp);

        return $resolvedIp;
    }

    private function validateIpAddress(string $ip): void {
        // Validate it's a proper IP
        if (!filter_var($ip, FILTER_VALIDATE_IP)) {
            throw new SsrfSecurityException('Invalid IP address format');
        }

        // Check against all blocked ranges
        foreach (self::BLOCKED_IP_RANGES as $range) {
            if ($this->ipInCidr($ip, $range)) {
                throw new SsrfSecurityException(
                    "Access to IP range {$range} is blocked"
                );
            }
        }
    }

    private function ipInCidr(string $ip, string $cidr): bool {
        // Handle IPv6
        if (strpos($cidr, ':') !== false) {
            return $this->ipv6InCidr($ip, $cidr);
        }

        list($subnet, $mask) = explode('/', $cidr);
        $ipLong = ip2long($ip);
        $subnetLong = ip2long($subnet);

        if ($ipLong === false || $subnetLong === false) {
            return false;
        }

        $maskLong = -1 << (32 - (int)$mask);
        return ($ipLong & $maskLong) === ($subnetLong & $maskLong);
    }

    private function ipv6InCidr(string $ip, string $cidr): bool {
        if (!filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV6)) {
            return false;
        }

        list($subnet, $mask) = explode('/', $cidr);
        $ipBin = inet_pton($ip);
        $subnetBin = inet_pton($subnet);

        if ($ipBin === false || $subnetBin === false) {
            return false;
        }

        $maskBits = (int)$mask;
        $ipBits = '';
        $subnetBits = '';

        for ($i = 0; $i < 16; $i++) {
            $ipBits .= str_pad(decbin(ord($ipBin[$i])), 8, '0', STR_PAD_LEFT);
            $subnetBits .= str_pad(decbin(ord($subnetBin[$i])), 8, '0', STR_PAD_LEFT);
        }

        return substr($ipBits, 0, $maskBits) === substr($subnetBits, 0, $maskBits);
    }

    private function validateAllowlist(string $host): void {
        $allowed = false;
        foreach ($this->config['allowed_domains'] as $domain) {
            if ($host === $domain || str_ends_with($host, '.' . $domain)) {
                $allowed = true;
                break;
            }
        }

        if (!$allowed) {
            throw new SsrfSecurityException(
                "Domain {$host} not in allowlist"
            );
        }
    }

    private function executeRequestWithPinnedIp(
        string $url,
        string $host,
        string $resolvedIp,
        string $requestId
    ): array {
        $ch = curl_init();

        // Replace host with resolved IP to prevent DNS rebinding
        // Use Host header to maintain virtual hosting
        $pinnedUrl = preg_replace(
            '/\/\/[^\/]+/',
            '//' . $resolvedIp,
            $url
        );

        curl_setopt_array($ch, [
            CURLOPT_URL => $pinnedUrl,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => false,  // CRITICAL: No redirects
            CURLOPT_MAXREDIRS => 0,
            CURLOPT_TIMEOUT => $this->config['timeout'],
            CURLOPT_CONNECTTIMEOUT => 5,
            CURLOPT_PROTOCOLS => CURLPROTO_HTTP | CURLPROTO_HTTPS,
            CURLOPT_REDIR_PROTOCOLS => 0,
            CURLOPT_HTTPHEADER => [
                "Host: {$host}",  // Preserve original host
                "X-Request-ID: {$requestId}"
            ],
            CURLOPT_SSL_VERIFYPEER => true,
            CURLOPT_SSL_VERIFYHOST => 2,
            // Limit response size
            CURLOPT_NOPROGRESS => false,
            CURLOPT_PROGRESSFUNCTION => function(
                $ch, $downloadSize, $downloaded
            ) {
                if ($downloaded > $this->config['max_response_size']) {
                    return 1; // Abort transfer
                }
                return 0;
            }
        ]);

        $content = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $effectiveUrl = curl_getinfo($ch, CURLINFO_EFFECTIVE_URL);
        $error = curl_error($ch);
        $errno = curl_errno($ch);
        curl_close($ch);

        if ($errno !== 0) {
            throw new SsrfSecurityException("cURL error: {$error}");
        }

        // Verify no redirect occurred (defense in depth)
        if ($effectiveUrl !== $pinnedUrl) {
            throw new SsrfSecurityException('Unexpected redirect detected');
        }

        return [
            'content' => $content,
            'status' => $httpCode,
            'request_id' => $requestId
        ];
    }

    private function validateResponse(array $result, string $requestId): void {
        // Check for signs of internal service access in response
        $suspiciousPatterns = [
            '/iam\/security-credentials/i',
            '/instance-identity/i',
            '/meta-data/i',
            '/computeMetadata/i'
        ];

        foreach ($suspiciousPatterns as $pattern) {
            if (preg_match($pattern, $result['content'])) {
                $this->logger->alert('Possible metadata access in response', [
                    'request_id' => $requestId,
                    'pattern' => $pattern
                ]);
                throw new SsrfSecurityException('Suspicious response content');
            }
        }
    }

    private function logSuccess(
        string $requestId,
        string $url,
        string $resolvedIp,
        string $requesterId,
        float $startTime
    ): void {
        $this->logger->info('SSRF request completed', [
            'request_id' => $requestId,
            'url' => $url,
            'resolved_ip' => $resolvedIp,
            'requester_id' => $requesterId,
            'duration_ms' => (microtime(true) - $startTime) * 1000
        ]);
    }

    private function logSecurityEvent(
        string $requestId,
        string $url,
        string $requesterId,
        SsrfSecurityException $e
    ): void {
        $this->logger->warning('SSRF security event', [
            'request_id' => $requestId,
            'url' => $url,
            'requester_id' => $requesterId,
            'reason' => $e->getMessage(),
            'timestamp' => date('c')
        ]);
    }

    private function logError(
        string $requestId,
        string $url,
        string $requesterId,
        \Exception $e
    ): void {
        $this->logger->error('SSRF request error', [
            'request_id' => $requestId,
            'url' => $url,
            'requester_id' => $requesterId,
            'error' => $e->getMessage()
        ]);
    }
}

