  if (BLOCKED_HOSTNAMES.includes(hostname)) {
    return { safe: false, reason: 'Blocked hostname' };
  }

  // Check if IP address directly
  if (net.isIP(hostname)) {
    for (const range of BLOCKED_IP_RANGES) {
      if (range.test(hostname)) {
        return { safe: false, reason: 'Internal IP address blocked' };
      }
    }
  }

  // DNS resolution check - prevent DNS rebinding
  try {
    const addresses = await dns.resolve4(hostname);
    for (const ip of addresses) {
      for (const range of BLOCKED_IP_RANGES) {
        if (range.test(ip)) {
          return { safe: false, reason: 'Hostname resolves to internal IP' };
        }
      }
    }
  } catch (dnsError) {
    return { safe: false, reason: 'DNS resolution failed' };
  }

  return { safe: true, url: parsedUrl };
}

