```java
import java.io.*;
import java.net.*;
import java.util.*;
import java.util.regex.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUrlFetcherServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureUrlFetcherServlet.class);

    // Allowlist of permitted domains
    private static final Set<String> ALLOWED_DOMAINS = Set.of(
        "api.trusted-partner.com",
        "cdn.example.com",
        "public-data.gov"
    );

    // Blocked IP ranges (private, loopback, link-local, metadata)
    private static final List<String> BLOCKED_IP_PATTERNS = Arrays.asList(
        "^127\\.",                    // Loopback
        "^10\\.",                     // Private Class A
        "^172\\.(1[6-9]|2[0-9]|3[01])\\.", // Private Class B
        "^192\\.168\\.",              // Private Class C
        "^169\\.254\\.",              // Link-local/metadata
        "^0\\.",                      // Current network
        "^::1$",                      // IPv6 loopback
        "^fc00:",                     // IPv6 private
        "^fe80:"                      // IPv6 link-local
    );

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String targetUrl = request.getParameter("url");
        String remoteAddr = request.getRemoteAddr();

        if (targetUrl == null || targetUrl.isEmpty()) {
            response.sendError(400, "URL parameter required");
            return;
        }

        try {
            // Validate and fetch securely
            String content = fetchUrlSecurely(targetUrl, remoteAddr);
            response.setContentType("text/plain");
            response.getWriter().write(content);
        } catch (SecurityException e) {
            logger.warn("SSRF attempt blocked from {}: {} - URL: {}", 
                remoteAddr, e.getMessage(), targetUrl);
            response.sendError(403, "URL not allowed");
        }
    }

    private String fetchUrlSecurely(String targetUrl, String clientIp) 
            throws IOException, SecurityException {

        // Step 1: Parse and validate URL structure
        URL url;
        try {
            url = new URL(targetUrl);
        } catch (MalformedURLException e) {
            throw new SecurityException("Invalid URL format");
        }

        // Step 2: Only allow HTTPS
        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new SecurityException("Only HTTPS protocol allowed");
        }

        // Step 3: Validate against domain allowlist
        String host = url.getHost().toLowerCase();
        if (!ALLOWED_DOMAINS.contains(host)) {
            throw new SecurityException("Domain not in allowlist: " + host);
        }

        // Step 4: Resolve hostname and validate IP
        InetAddress[] addresses = InetAddress.getAllByName(host);
        for (InetAddress addr : addresses) {
            if (isBlockedIP(addr.getHostAddress())) {
                throw new SecurityException("Resolved IP is blocked");
            }
        }

        // Step 5: Fetch with restricted connection
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod("GET");
        conn.setConnectTimeout(5000);
        conn.setReadTimeout(10000);
        conn.setInstanceFollowRedirects(false); // Prevent redirect to internal URLs

        int responseCode = conn.getResponseCode();
        if (responseCode != 200) {
            throw new IOException("Unexpected response: " + responseCode);
        }

        BufferedReader reader = new BufferedReader(
            new InputStreamReader(conn.getInputStream()));
        StringBuilder content = new StringBuilder();
        String line;
        int maxLength = 1024 * 1024; // 1MB limit
        while ((line = reader.readLine()) != null && content.length() < maxLength) {
            content.append(line);
        }
        reader.close();

        logger.info("Successfully fetched URL for client {}: {}", clientIp, host);
        return content.toString();
    }

    private boolean isBlockedIP(String ip) {
        for (String pattern : BLOCKED_IP_PATTERNS) {
            if (Pattern.matches(pattern, ip)) {
                return true;
            }
        }
        return false;
    }
}
```

**Key Security Controls**:
- **Domain Allowlist**: Only explicitly trusted domains can be accessed
- **Protocol Restriction**: Only HTTPS allowed, blocking file://, gopher://, etc.
- **IP Validation**: Blocks private, loopback, and metadata IP ranges after DNS resolution
- **Redirect Prevention**: Disables automatic redirects that could bypass checks
- **Response Size Limit**: Prevents resource exhaustion attacks

Excellent questions! DNS rebinding is a sophisticated attack where an attacker controls a domain that initially resolves to a safe IP, then quickly changes to an internal IP between your validation and actual request. Safe redirect handling requires validating each hop.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.net.*;
import java.time.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;
import javax.net.ssl.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class ProductionSSRFProtectedClient {
    private static final Logger logger = LoggerFactory.getLogger(ProductionSSRFProtectedClient.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // DNS cache to prevent rebinding
    private static final ConcurrentHashMap<String, CachedDNS> dnsCache = new ConcurrentHashMap<>();
    private static final long DNS_CACHE_TTL_MS = 300000; // 5 minutes

    private static final Set<String> ALLOWED_DOMAINS = Set.of(
        "api.trusted-partner.com",
        "cdn.example.com"
    );

    private static final int MAX_REDIRECTS = 3;
    private static final int MAX_RESPONSE_SIZE = 5 * 1024 * 1024; // 5MB
    private static final int CONNECT_TIMEOUT = 5000;
    private static final int READ_TIMEOUT = 30000;

    // Comprehensive blocked CIDR ranges
    private static final List<InetAddressRange> BLOCKED_RANGES = initBlockedRanges();

    private static List<InetAddressRange> initBlockedRanges() {
        List<InetAddressRange> ranges = new ArrayList<>();
        try {
            // Private networks
            ranges.add(new InetAddressRange("10.0.0.0", 8));
            ranges.add(new InetAddressRange("172.16.0.0", 12));
            ranges.add(new InetAddressRange("192.168.0.0", 16));
            // Loopback
            ranges.add(new InetAddressRange("127.0.0.0", 8));
            // Link-local and cloud metadata
            ranges.add(new InetAddressRange("169.254.0.0", 16));
            // Current network
            ranges.add(new InetAddressRange("0.0.0.0", 8));
            // Carrier-grade NAT
            ranges.add(new InetAddressRange("100.64.0.0", 10));
        } catch (Exception e) {
            logger.error("Failed to initialize blocked ranges", e);
        }
        return ranges;
    }

    public FetchResult fetchUrl(String targetUrl, String requestId, String clientIp) {
        Instant startTime = Instant.now();

        try {
            // Validate initial URL
            ValidatedURL validatedUrl = validateAndResolve(targetUrl, requestId);

            // Fetch with safe redirect handling
            String content = fetchWithSafeRedirects(validatedUrl, requestId, clientIp);

            auditLogger.info("SSRF_FETCH_SUCCESS|requestId={}|clientIp={}|host={}|duration={}ms",
                requestId, clientIp, validatedUrl.host, 
                Duration.between(startTime, Instant.now()).toMillis());

            return new FetchResult(true, content, null);

        } catch (SSRFBlockedException e) {
            auditLogger.warn("SSRF_BLOCKED|requestId={}|clientIp={}|url={}|reason={}",
                requestId, clientIp, targetUrl, e.getMessage());
            return new FetchResult(false, null, "Request blocked: " + e.getMessage());
        } catch (Exception e) {
            logger.error("Fetch error for request {}: {}", requestId, e.getMessage());
            return new FetchResult(false, null, "Fetch failed");
        }
    }

    private ValidatedURL validateAndResolve(String urlString, String requestId) 
            throws SSRFBlockedException {
        URL url;
        try {
            url = new URL(urlString);
        } catch (MalformedURLException e) {
            throw new SSRFBlockedException("Invalid URL format");
        }

        // Protocol validation
        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new SSRFBlockedException("Only HTTPS allowed");
        }

        String host = url.getHost().toLowerCase();

        // Domain allowlist check
        if (!ALLOWED_DOMAINS.contains(host)) {
            throw new SSRFBlockedException("Domain not allowed: " + host);
        }

        // Resolve and cache DNS to prevent rebinding
        InetAddress resolvedAddr = resolveWithCache(host, requestId);

        // Validate resolved IP
        validateIP(resolvedAddr, host);

        return new ValidatedURL(url, host, resolvedAddr);
    }

    private InetAddress resolveWithCache(String host, String requestId) 
            throws SSRFBlockedException {
        // Check cache first
        CachedDNS cached = dnsCache.get(host);
        if (cached != null && !cached.isExpired()) {
            logger.debug("DNS cache hit for {}", host);
            return cached.address;
        }

        // Resolve with custom DNS resolver to avoid system cache
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            if (addresses.length == 0) {
                throw new SSRFBlockedException("No DNS records found");
            }

            InetAddress selectedAddr = addresses[0];

            // Cache the resolution to prevent rebinding
            dnsCache.put(host, new CachedDNS(selectedAddr, 
                System.currentTimeMillis() + DNS_CACHE_TTL_MS));

            logger.debug("Resolved {} to {} for request {}", host, selectedAddr, requestId);
            return selectedAddr;

        } catch (UnknownHostException e) {
            throw new SSRFBlockedException("DNS resolution failed");
        }
    }

    private void validateIP(InetAddress addr, String host) throws SSRFBlockedException {
        // Check against blocked ranges
        for (InetAddressRange range : BLOCKED_RANGES) {
            if (range.contains(addr)) {
                throw new SSRFBlockedException(
                    "Resolved IP in blocked range for host: " + host);
            }
        }

        // Additional checks
        if (addr.isLoopbackAddress() || addr.isLinkLocalAddress() ||
            addr.isSiteLocalAddress() || addr.isAnyLocalAddress()) {
            throw new SSRFBlockedException("Internal IP detected for host: " + host);
        }
    }

    private String fetchWithSafeRedirects(ValidatedURL validatedUrl, 
            String requestId, String clientIp) throws Exception {

        URL currentUrl = validatedUrl.url;
        InetAddress currentAddr = validatedUrl.resolvedAddress;
        int redirectCount = 0;

        while (redirectCount <= MAX_REDIRECTS) {
            // Create socket factory that binds to validated IP
            HttpsURLConnection conn = createBoundConnection(currentUrl, currentAddr);

            conn.setRequestMethod("GET");
            conn.setConnectTimeout(CONNECT_TIMEOUT);
            conn.setReadTimeout(READ_TIMEOUT);
            conn.setInstanceFollowRedirects(false);
            conn.setRequestProperty("User-Agent", "SecureClient/1.0");

            int responseCode = conn.getResponseCode();

            // Handle redirects safely
            if (responseCode >= 300 && responseCode < 400) {
                String location = conn.getHeaderField("Location");
                if (location == null) {
                    throw new SSRFBlockedException("Redirect without Location header");
                }

                // Validate redirect URL through same process
                ValidatedURL redirectValidated = validateAndResolve(location, requestId);
                currentUrl = redirectValidated.url;
                currentAddr = redirectValidated.resolvedAddress;
                redirectCount++;

                logger.info("Safe redirect {} -> {} for request {}", 
                    validatedUrl.host, redirectValidated.host, requestId);
                continue;
            }

            if (responseCode != 200) {
                throw new IOException("Unexpected response code: " + responseCode);
            }

            // Read response with size limit
            return readResponseWithLimit(conn.getInputStream());
        }

        throw new SSRFBlockedException("Too many redirects");
    }

    private HttpsURLConnection createBoundConnection(URL url, InetAddress addr) 
            throws Exception {
        // Create connection bound to specific IP to prevent DNS rebinding
        int port = url.getPort() == -1 ? 443 : url.getPort();

        SSLSocketFactory factory = (SSLSocketFactory) SSLSocketFactory.getDefault();
        SSLSocket socket = (SSLSocket) factory.createSocket(addr, port);

        // SNI for correct certificate validation
        SSLParameters params = socket.getSSLParameters();
        params.setServerNames(Collections.singletonList(
            new SNIHostName(url.getHost())));
        socket.setSSLParameters(params);

        // Create URL connection using bound socket
        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();
        return conn;
    }

    private String readResponseWithLimit(InputStream is) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] data = new byte[8192];
        int bytesRead;
        int totalRead = 0;

        while ((bytesRead = is.read(data)) != -1) {
            totalRead += bytesRead;
            if (totalRead > MAX_RESPONSE_SIZE) {
                throw new IOException("Response exceeds size limit");
            }
            buffer.write(data, 0, bytesRead);
        }

        return buffer.toString("UTF-8");
    }

    // Helper classes
    private static class ValidatedURL {
        final URL url;
        final String host;
        final InetAddress resolvedAddress;

        ValidatedURL(URL url, String host, InetAddress addr) {
            this.url = url;
            this.host = host;
            this.resolvedAddress = addr;
        }
    }

    private static class CachedDNS {
        final InetAddress address;
        final long expiresAt;

        CachedDNS(InetAddress address, long expiresAt) {
            this.address = address;
            this.expiresAt = expiresAt;
        }

        boolean isExpired() {
            return System.currentTimeMillis() > expiresAt;
        }
    }

    private static class InetAddressRange {
        private final byte[] network;
        private final int prefixLength;

        InetAddressRange(String cidr, int prefix) throws UnknownHostException {
            this.network = InetAddress.getByName(cidr).getAddress();
            this.prefixLength = prefix;
        }

        boolean contains(InetAddress addr) {
            byte[] addrBytes = addr.getAddress();
            if (addrBytes.length != network.length) return false;

            int fullBytes = prefixLength / 8;
            int remainingBits = prefixLength % 8;

            for (int i = 0; i < fullBytes; i++) {
                if (addrBytes[i] != network[i]) return false;
            }

            if (remainingBits > 0 && fullBytes < addrBytes.length) {
                int mask = 0xFF << (8 - remainingBits);
                if ((addrBytes[fullBytes] & mask) != (network[fullBytes] & mask)) {
                    return false;
                }
            }

            return true;
        }
    }

    public static class FetchResult {
        public final boolean success;
        public final String content;
        public final String error;

        FetchResult(boolean success, String content, String error) {
            this.success = success;
            this.content = content;
            this.error = error;
        }
    }

    public static class SSRFBlockedException extends Exception {
        public SSRFBlockedException(String message) {
            super(message);
        }
    }
}
