**Key Security Controls**:
- **Domain whitelist**: Only explicitly allowed domains can be fetched
- **IP validation**: Blocks private/reserved IP ranges including cloud metadata (169.254.x.x)
- **Scheme restriction**: Only HTTPS allowed, preventing file:// and other dangerous schemes
- **Redirect validation**: Each redirect destination is validated against the same rules
- **Response size limits**: Prevents memory exhaustion attacks

When you can't use a whitelist, you need multiple layers of defense including DNS rebinding protection. DNS rebinding attacks work by having a malicious DNS server return a public IP initially (passing validation) then switching to an internal IP for the actual request.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/tls"
	"errors"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

var (
	ErrBlockedIP      = errors.New("blocked IP address")
	ErrBlockedHost    = errors.New("blocked hostname")
	ErrInvalidScheme  = errors.New("invalid URL scheme")
	ErrTooManyRetries = errors.New("too many redirect attempts")
)

// SSRFProtector provides comprehensive SSRF protection
type SSRFProtector struct {
	privateBlocks []*net.IPNet
	blockedHosts  map[string]bool
	maxRedirects  int
	timeout       time.Duration
	maxBodySize   int64
	logger        *log.Logger
	resolveCache  sync.Map
}

// NewSSRFProtector creates a new protector with security defaults
func NewSSRFProtector(logger *log.Logger) *SSRFProtector {
	blocks := []string{
		"0.0.0.0/8",          // Current network
		"10.0.0.0/8",         // Private class A
		"100.64.0.0/10",      // Carrier-grade NAT
		"127.0.0.0/8",        // Localhost
		"169.254.0.0/16",     // Link-local (AWS/Azure metadata)
		"172.16.0.0/12",      // Private class B
		"192.0.0.0/24",       // IETF Protocol assignments
		"192.0.2.0/24",       // TEST-NET-1
		"192.88.99.0/24",     // 6to4 relay
		"192.168.0.0/16",     // Private class C
		"198.18.0.0/15",      // Network benchmark
		"198.51.100.0/24",    // TEST-NET-2
		"203.0.113.0/24",     // TEST-NET-3
		"224.0.0.0/4",        // Multicast
		"240.0.0.0/4",        // Reserved
		"255.255.255.255/32", // Broadcast
		"::1/128",            // IPv6 localhost
		"fc00::/7",           // IPv6 private
		"fe80::/10",          // IPv6 link-local
	}

	var privateBlocks []*net.IPNet
	for _, block := range blocks {
		_, cidr, _ := net.ParseCIDR(block)
		privateBlocks = append(privateBlocks, cidr)
	}

	// Block known metadata hostnames
	blockedHosts := map[string]bool{
		"metadata.google.internal":         true,
		"metadata.goog":                    true,
		"kubernetes.default.svc":           true,
		"kubernetes.default":               true,
		"localhost":                        true,
	}

	return &SSRFProtector{
		privateBlocks: privateBlocks,
		blockedHosts:  blockedHosts,
		maxRedirects:  3,
		timeout:       15 * time.Second,
		maxBodySize:   10 * 1024 * 1024, // 10MB
		logger:        logger,
	}
}

// isBlockedIP checks if IP is in blocked ranges
func (p *SSRFProtector) isBlockedIP(ip net.IP) bool {
	for _, block := range p.privateBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// resolveAndValidate resolves hostname and validates all IPs
func (p *SSRFProtector) resolveAndValidate(hostname string) ([]net.IP, error) {
	// Check blocked hostnames
	lowerHost := strings.ToLower(hostname)
	if p.blockedHosts[lowerHost] {
		return nil, ErrBlockedHost
	}

	// Check if it's already an IP
	if ip := net.ParseIP(hostname); ip != nil {
		if p.isBlockedIP(ip) {
			return nil, ErrBlockedIP
		}
		return []net.IP{ip}, nil
	}

	// Resolve DNS with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", hostname)
	if err != nil {
		return nil, fmt.Errorf("DNS resolution failed: %w", err)
	}

	// Validate ALL resolved IPs
	var validIPs []net.IP
	for _, ip := range ips {
		if p.isBlockedIP(ip) {
			p.logger.Printf("SECURITY: Blocked IP %s for hostname %s", ip, hostname)
			return nil, ErrBlockedIP
		}
		validIPs = append(validIPs, ip)
	}

	return validIPs, nil
}

// createSafeDialer creates a dialer that validates IPs at connection time
// This prevents DNS rebinding attacks!
func (p *SSRFProtector) createSafeDialer() *net.Dialer {
	return &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 30 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}

			ip := net.ParseIP(host)
			if ip != nil && p.isBlockedIP(ip) {
				p.logger.Printf("SECURITY: DNS rebinding attempt blocked: %s", address)
				return ErrBlockedIP
			}
			return nil
		},
	}
}

// CreateSafeClient creates an HTTP client with SSRF protections
func (p *SSRFProtector) CreateSafeClient() *http.Client {
	dialer := p.createSafeDialer()

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Extract hostname and validate before connecting
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve and validate at connection time (DNS rebinding protection)
			ips, err := p.resolveAndValidate(host)
			if err != nil {
				return nil, err
			}

			// Connect to validated IP directly
			for _, ip := range ips {
				target := net.JoinHostPort(ip.String(), port)
				conn, err := dialer.DialContext(ctx, network, target)
				if err == nil {
					return conn, nil
				}
			}
			return nil, fmt.Errorf("failed to connect to any resolved IP")
		},
		TLSClientConfig: &tls.Config{
			MinVersion: tls.VersionTLS12,
		},
		MaxIdleConns:        10,
		IdleConnTimeout:     30 * time.Second,
		DisableCompression:  true,
		ResponseHeaderTimeout: 10 * time.Second,
	}

	redirectCount := 0
	return &http.Client{
		Timeout:   p.timeout,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			redirectCount++
			if redirectCount > p.maxRedirects {
				return ErrTooManyRetries
			}

			// Validate redirect destination
			if req.URL.Scheme != "https" && req.URL.Scheme != "http" {
				return ErrInvalidScheme
			}

			_, err := p.resolveAndValidate(req.URL.Hostname())
			if err != nil {
				p.logger.Printf("SECURITY: Blocked redirect to %s: %v", req.URL.Host, err)
				return err
			}
			return nil
		},
	}
}

// Fetch safely retrieves content from a URL with full SSRF protection
func (p *SSRFProtector) Fetch(ctx context.Context, rawURL string) ([]byte, string, error) {
	// Parse and validate URL
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return nil, "", fmt.Errorf("invalid URL: %w", err)
	}

	// Scheme validation
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return nil, "", ErrInvalidScheme
	}

	// Pre-flight validation
	if _, err := p.resolveAndValidate(parsedURL.Hostname()); err != nil {
		return nil, "", err
	}

	// Create request with context
	req, err := http.NewRequestWithContext(ctx, "GET", parsedURL.String(), nil)
	if err != nil {
		return nil, "", err
	}

	// Set safe headers
	req.Header.Set("User-Agent", "SafeFetcher/1.0")
	req.Header.Del("Cookie") // Don't send cookies

	client := p.CreateSafeClient()
	resp, err := client.Do(req)
	if err != nil {
		return nil, "", fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	// Limit response size
	limitedReader := io.LimitReader(resp.Body, p.maxBodySize)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, "", fmt.Errorf("failed to read response: %w", err)
	}

	contentType := resp.Header.Get("Content-Type")
	p.logger.Printf("Successfully fetched %s (%d bytes)", parsedURL.Host, len(body))

	return body, contentType, nil
}

// Handler for HTTP endpoint
func createFetchHandler(protector *SSRFProtector) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userURL := r.URL.Query().Get("url")
		if userURL == "" {
			http.Error(w, "URL parameter required", http.StatusBadRequest)
			return
		}

		ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
		defer cancel()

		body, contentType, err := protector.Fetch(ctx, userURL)
		if err != nil {
			switch {
			case errors.Is(err, ErrBlockedIP), errors.Is(err, ErrBlockedHost):
				protector.logger.Printf("BLOCKED: %s from %s", userURL, r.RemoteAddr)
				http.Error(w, "Forbidden URL", http.StatusForbidden)
			case errors.Is(err, ErrInvalidScheme):
				http.Error(w, "Only HTTP/HTTPS allowed", http.StatusBadRequest)
			default:
				http.Error(w, "Failed to fetch URL", http.StatusBadGateway)
			}
			return
		}

		w.Header().Set("Content-Type", contentType)
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Write(body)
	}
}

func main() {
	logger := log.New(log.Writer(), "[SSRF-PROTECT] ", log.LstdFlags)
	protector := NewSSRFProtector(logger)

	http.HandleFunc("/fetch", createFetchHandler(protector))
	log.Fatal(http.ListenAndServe(":8080", nil))
}
